INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 115711, 0, 0, 920, 10, "衆人環視のフードコートでの犯行。\n移動系の魔法や魔道具の痕跡も無し。", 1, 11, 19200021, 0.5);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", 0, "", "", 920, "", "", "", 91, 19200022, "");
