INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 115711, 0, 0, 920, 10, "関係者のアリバイも完璧だったため\nおそらく犯人は外部の人間。", 1, 11, 19200027, 0.5);
