INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 115711, 0, 0, 921, 10, "フードコートで提供予定だった大量の\n料理がいつのまにか全て消失…", 1, 11, 19210017, 0.5);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", 0, "", "", 921, "", "", "", 91, 19210018, "");
