INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 115711, 0, 0, 921, 10, "今回の事件で不可解な点は目撃者たちが\nことごとく口をつぐんでいる点だ。", 1, 11, 19210023, 0.5);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", 0, "", "", 921, "", "", "", 91, 19210024, "");
