INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 110411, 0, 0, 945, 9, "わかったよ。あたしがついてって\nかわりに食ってやるから…\n他のおかずは自信作なんだろ？\nほら、早く行くぞ！", 1, 11, 19450037, 0.5);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", 0, "", "", 945, "", "", "", 91, 19450038, "");
